"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[39527],{95748:e=>{e.exports=JSON.parse('{"tag":{"label":"OpenAI API","permalink":"/1.0.0/tags/open-ai-api","allTagsPath":"/1.0.0/tags","count":11,"items":[{"id":"guides/asynchronous-requests","title":"Asynchronous Requests (Queue API)","description":"Submit long-running API requests to a queue for asynchronous processing. The Queue API mirrors the standard endpoints but processes requests in the background, making it ideal for batch workloads and large inference jobs.","permalink":"/1.0.0/guides/asynchronous-requests"},{"id":"guides/audio","title":"Audio (Speech-to-Text)","description":"AI Foundation Services provides Whisper-based audio models for transcription and translation, compatible with the OpenAI Audio API.","permalink":"/1.0.0/guides/audio"},{"id":"guides/chat-completions","title":"Chat Completions","description":"The Chat Completions API is the primary way to interact with LLMs on AI Foundation Services. It\'s fully compatible with the OpenAI Chat API.","permalink":"/1.0.0/guides/chat-completions"},{"id":"guides/embeddings","title":"Embeddings","description":"The Embedding API converts text into vector representations that capture semantic meaning. Use embeddings for semantic search, clustering, and RAG applications.","permalink":"/1.0.0/guides/embeddings"},{"id":"guides/fine-tuning","title":"Fine-Tuning","description":"Fine-tune models with your own data using techniques like LoRA and DPO with RLHF. The Fine-Tuning API is compatible with the OpenAI fine-tuning interface.","permalink":"/1.0.0/guides/fine-tuning"},{"id":"guides/function-calling","title":"Function Calling","description":"Function calling lets models generate structured JSON arguments for functions you define, enabling integration with external tools and APIs.","permalink":"/1.0.0/guides/function-calling"},{"id":"guides/image-generation","title":"Image Generation","description":"Generate images from text prompts using the OpenAI-compatible Images API.","permalink":"/1.0.0/guides/image-generation"},{"id":"guides/multimodal","title":"Multimodal (Vision)","description":"AI Foundation Services provides vision models that can analyze images alongside text. Use the same Chat Completions API with image content.","permalink":"/1.0.0/guides/multimodal"},{"id":"guides/reasoning","title":"Reasoning Control","description":"For models that support reasoning (chain-of-thought), you can control the depth of reasoning with the reasoning_effort parameter.","permalink":"/1.0.0/guides/reasoning"},{"id":"guides/streaming","title":"Streaming","description":"Stream responses token-by-token using Server-Sent Events (SSE) for faster time-to-first-token and a better user experience in interactive applications.","permalink":"/1.0.0/guides/streaming"},{"id":"guides/visual-rag","title":"Visual RAG","description":"Visual RAG indexes your files in both text and image, combining the stability of text indexing with the flexibility of visual indexing. It can retrieve information from graphs, charts, and complex table layouts that text-based RAG systems miss.","permalink":"/1.0.0/guides/visual-rag"}],"unlisted":false}}')}}]);